const execData  = $input.first().json;
const inputData = $('Execute Workflow Trigger').first().json;

const source = inputData.source || 'support_agent';

// Node name → token path mapping per source
const nodeTargets = {
  support_agent:    'OpenAI Chat Model',       // token usage lives here
  format_response:  'Format Webhook Response'  // unchanged
};

const targetNode = nodeTargets[source];

function extractTokens(runData, nodeName) {
  if (!runData || !nodeName || !runData[nodeName]) {
    return { promptTokens: 0, completionTokens: 0, totalTokens: 0 };
  }

  const steps = runData[nodeName];

  for (const step of steps) {
    // Check main output (usual for most nodes)
    const outputs = step?.data?.main || [];
    for (const output of outputs) {
      for (const item of (output || [])) {
        const json = item?.json || {};
        const tokens = findTokenUsage(json);
        if (tokens) return tokens;
      }
    }

    // Check ai_languageModel output (used by OpenAI Chat Model node)
    const aiOutputs = step?.data?.ai_languageModel || [];
    for (const output of aiOutputs) {
      for (const item of (output || [])) {
        const json = item?.json || {};
        const tokens = findTokenUsage(json);
        if (tokens) return tokens;
      }
    }

    // Add other output keys if necessary (e.g., ai_memory, ai_tool)
  }

  return { promptTokens: 0, completionTokens: 0, totalTokens: 0 };
}

// Helper to scan various possible token‑usage locations in a JSON object
function findTokenUsage(json) {
  // Direct OpenAI node → json.usage
  if (json.usage) {
    return {
      promptTokens:     json.usage.prompt_tokens     || 0,
      completionTokens: json.usage.completion_tokens || 0,
      totalTokens:      json.usage.total_tokens      || 0
    };
  }

  // Langchain agent node → json.response.tokenUsageEstimate
  if (json.response?.tokenUsageEstimate) {
    const u = json.response.tokenUsageEstimate;
    return {
      promptTokens:     u.promptTokens     || 0,
      completionTokens: u.completionTokens || 0,
      totalTokens:      u.totalTokens      || 0
    };
  }

  // Langchain agent node → json.tokenUsageEstimate (flat)
  if (json.tokenUsageEstimate) {
    const u = json.tokenUsageEstimate;
    return {
      promptTokens:     u.promptTokens     || 0,
      completionTokens: u.completionTokens || 0,
      totalTokens:      u.totalTokens      || 0
    };
  }

  return null;
}

const runData    = execData?.data?.resultData?.runData || {};
const tokens     = extractTokens(runData, targetNode);

return [{
  json: {
    userId:           inputData.userId          || null,
    organizationId:   inputData.organizationId  || null,
    source:           source,
    model:            inputData.model           || null,
    inputMessage:     inputData.inputMessage    || '',
    parsedMessage:    inputData.parsedMessage   || '',
    intent:           inputData.intent          || null,
    action:           inputData.action          || null,
    promptTokens:     tokens.promptTokens,
    completionTokens: tokens.completionTokens,
    totalTokens:      tokens.totalTokens,
    executionId:      inputData.executionId     || null,
    timestamp:        new Date().toISOString()
  }
}];
